1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	const COMPONENT_PREMIUM = 25;
11	const COMPONENT_BLOCK_PREMIUM = 60;
12	const COMPONENT_BLOCK_SIZE = 3;
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	const FIRST_INSURANCE_RATE = 0.1;
16	const LOYALTY_DISCOUNT_RATE = 0.2;
17	const LOYALTY_YEARS_THRESHOLD = 2;
18	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
19	const CURSED_SURCHARGE_RATE = 0.5;
20	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
21	const HIGH_ENCHANTMENT_THRESHOLD = 5;
22	
23	const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);
24	
25	const itemBasePremium = (item: any): number => BASE_PREMIUMS[item.type] ?? 0;
26	
27	function countByType(components: any[]): Record<string, number> {
28	  const counts: Record<string, number> = {};
29	  for (const c of components) {
30	    counts[c.type] = (counts[c.type] ?? 0) + 1;
31	  }
32	  return counts;
33	}
34	
35	function componentGroupPremium(count: number): number {
36	  return count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
37	}
38	
39	function componentPremium(items: any[]): number {
40	  const components = items.filter(isComponent);
41	  const typeCounts = countByType(components);
42	  return Object.values(typeCounts).reduce(
43	    (sum, count) => sum + componentGroupPremium(count),
44	    0,
45	  );
46	}
47	
48	function itemSurcharge(item: any): number {
49	  const base = itemBasePremium(item);
50	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
51	  const enchantmentSurcharge = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
52	  return cursedSurcharge + enchantmentSurcharge;
53	}
54	
55	function validateItems(items: any[]): void {
56	  for (const item of items) {
57	    if (!BASE_PREMIUMS[item.type] && !COMPONENT_TYPES.has(item.type)) {
58	      throw new Error(`Unknown item type: ${item.type}`);
59	    }
60	  }
61	}
62	
63	function calculateQuotePremium(items: any[], customer: any, quoteIndex: number): number {
64	  validateItems(items);
65	  const mainItems = items.filter((item: any) => !isComponent(item));
66	  const mainBase = mainItems.reduce(
67	    (sum: number, item: any) => sum + itemBasePremium(item),
68	    0,
69	  );
70	  const mainSurcharges = mainItems.reduce(
71	    (sum: number, item: any) => sum + itemSurcharge(item),
72	    0,
73	  );
74	  const componentTotal = componentPremium(items);
75	  const policyBase = mainBase + componentTotal;
76	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
77	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
78	  const followUpDiscount = quoteIndex > 0 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
79	  return Math.ceil(policyBase + mainSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
80	}
81	
82	export function processScenario(scenario: any): { results: { premium: number }[] } {
83	  let quoteCount = 0;
84	  const results = scenario.steps.map((step: any) => {
85	    const premium = calculateQuotePremium(step.items, scenario.customer, quoteCount);
86	    quoteCount++;
87	    return { premium };
88	  });
89	  return { results };
90	}
