80	  const followUpDiscount = quoteIndex > 0 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
81	  return Math.ceil(policyBase + standardSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
82	}
